import React, { useRef, useState } from 'react';
import { Button, Card, message, Space, Modal, Input, Form, Breadcrumb } from 'antd';
import { useForm } from 'antd/lib/form/Form';
import { useModel } from '@umijs/max';
import type { CheckboxChangeEvent } from 'antd/es/checkbox';
import type { ProFormInstance } from '@ant-design/pro-form';
import ProForm, { ProFormDigit, ProFormText, ProFormCheckbox, ProFormSelect } from '@ant-design/pro-form';
import {
  teamInfo as queryTeamInfo,
  updateTeamInfo,
} from '@/services/api';

import { get_base_url, t } from '@/global';
import type { API } from '@/services/typings';
import { PageContainer } from '@ant-design/pro-layout';


const SmtpView: React.FC = () => {
  const { initialState } = useModel('@@initialState');
  const { loading } = initialState!;

  const [requiresAuth, setRequiresAuth] = useState(true);
  const [account, setAccount] = useState('');
  const [password, setPassword] = useState('');
  const [oauth2Enabled, setOauth2Enabled] = useState(false);
  const [oauth2Provider, setOauth2Provider] = useState('');

  const [waitingUpdate, setWaitingUpdate] = useState(false);

  const [testEmailModalvisible, setTestEmailModalvisible] = useState(false);
  const [testReceiver, setTestReceiver] = useState('');
  const [waitingTestEmail, setWaitingTestEmail] = useState(false);

  const [testEmailSuccessMsg, setTestEmailSuccessMsg] = useState<string | undefined>(undefined);
  const [testEmailFailureMsg, setTestEmailFailureMsg] = useState<string | undefined>(undefined);
  const [testEmailRetryMsg, setTestEmailRetryMsg] = useState<string | undefined>(undefined);

  const formRef = useRef<ProFormInstance<API.TeamInfo>>();
  const [testReceiverForm] = useForm();

  const handleFinish = async (info: API.TeamInfo) => {
    setTestEmailSuccessMsg(undefined);
    setTestEmailFailureMsg(undefined);
    setTestEmailRetryMsg(undefined);
    setWaitingUpdate(true);
    try {
      info.smtp!.base_url = get_base_url();
      const resp = await updateTeamInfo({ data: info });

      if (resp.code === 0) {
        setAccount(info.smtp!.account!);
        setPassword(info.smtp!.password!);
        message.success('Update SMTP Info successfully.');
        // If auth is not required (and not oauth2), do not show the detailed test result.
        if (info.smtp!.requires_auth || info.smtp!.oauth2_provider) {
          setTestEmailSuccessMsg(resp.msg);
        }
      } else {
        // If the code is not 0, the backend will not update the settings.
        message.error('Failed to update SMTP');
        if (resp.can_retry) {
          setTestEmailRetryMsg(resp.msg);
        } else {
          setTestEmailFailureMsg(resp.msg);
        }
      }
    } catch (error) {
      setWaitingTestEmail(false);
      message.error('Failed to update SMTP');
      setTestEmailFailureMsg('' + error);
    }
    setWaitingUpdate(false);
  };

  const handleFinishAndTestEmail = async () => {
    try {
      await formRef.current?.validateFields();
      setTestEmailModalvisible(true);
    } catch (error) {
    }
  }

  const formAccountPassword = () => {
    return <>
      <ProForm.Group>
        <ProFormText
          fieldProps={{
            autoComplete: 'off',
            onChange: (e) => {
              setAccount(e.target.value);
            }
          }}
          rules={[
            {
              required: true,
              whitespace: true,
            },
            {
              max: 300,
            },
          ]}
          width="md"
          name={['smtp', 'account']}
          label={t('Mail Account', true)}
        />
        {!oauth2Enabled && (
          <ProFormText.Password
            rules={[
              {
                required: true,
                whitespace: true,
              },
            ]}
            width="md"
            name={['smtp', 'password']}
            label={t('Mail Password', true)}
            fieldProps={{
              onChange: (e) => {
                setPassword(e.target.value);
              }
            }}
          />
        )}
      </ProForm.Group>
    </>;
  }

  const formOauth2Fields = () => {
    return <>
      {oauth2Provider === 'M365' && (
        <ProFormText
          fieldProps={{ autoComplete: 'off' }}
          rules={[
            {
              required: true,
              whitespace: true,
            },
          ]}
          width="md"
          name={['smtp', 'oauth2_tenant_id']}
          label={t('OAuth2 Tenant ID', true)}
          placeholder={'xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx'}
        />
      )}
      {oauth2Provider === 'Custom' && (
        <ProForm.Group>
          <ProFormText
            fieldProps={{ autoComplete: 'off' }}
            rules={[
              {
                required: true,
                whitespace: true,
              },
            ]}
            width="md"
            name={['smtp', 'oauth2_token_url']}
            label={t('OAuth2 Token URL', true)}
            placeholder={'https://login.microsoftonline.com/{tenant}/oauth2/v2.0/token'}
          />
          <ProFormText
            fieldProps={{ autoComplete: 'off' }}
            rules={[
              {
                required: true,
                whitespace: true,
              },
            ]}
            width="md"
            name={['smtp', 'oauth2_scope']}
            label={t('OAuth2 Scope', true)}
            placeholder={'https://outlook.office365.com/.default'}
          />
        </ProForm.Group>
      )}
      <ProForm.Group>
        <ProFormText
          fieldProps={{ autoComplete: 'off' }}
          rules={[
            {
              required: true,
              whitespace: true,
            },
          ]}
          width="md"
          name={['smtp', 'oauth2_client_id']}
          label={t('OAuth2 Client ID', true)}
          placeholder={'xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx'}
        />
        <ProFormText.Password
          rules={[
            {
              required: true,
              whitespace: true,
            },
          ]}
          width="md"
          name={['smtp', 'oauth2_client_secret']}
          label={t('OAuth2 Client Secret', true)}
          // Hint only, no expiry-date setting – the OAuth2 token endpoint does not
          // return the secret's expiration, manual entry is error-prone, and a single
          // secret may be shared across apps. Credential lifecycle monitoring belongs
          // on the IdP side (e.g. Azure Logic Apps / Power Automate).
          extra={<span style={{ display: 'inline-block', maxWidth: 328 }}>{t('Client secrets have an expiration date. Set a calendar reminder before it expires to avoid service interruption.', true)}</span>}
        />
      </ProForm.Group>
    </>;
  }

  const formSubmitButton = () => {
    return <>
      <Button
        type='primary'
        loading={waitingUpdate}
        onClick={formRef.current?.submit}
      >
        {t('Update', true)}
      </Button>
    </>;
  }

  const formSubmitAndTestButton = () => {
    return <>
      <Button
        type='primary'
        loading={waitingTestEmail}
        onClick={handleFinishAndTestEmail}
      >
        {t('Submit and Test Email', true)}
      </Button>
    </>;
  }

  const testEmailResult = () => {
    return (
      <>
        {testEmailSuccessMsg && (
          <>
            <div style={{ color: 'green', whiteSpace: 'pre-line' }}>{testEmailSuccessMsg}</div>
            <br />
          </>
        )}
        {testEmailFailureMsg && (
          <>
            <div style={{ color: 'red', whiteSpace: 'pre-line' }}>{testEmailFailureMsg}</div>
            <br />
          </>
        )}
        {testEmailRetryMsg && (
          <>
            <div style={{ color: 'orange', whiteSpace: 'pre-line' }}>{testEmailRetryMsg}</div>
            <div>
              <span style={{ fontWeight: 'bold' }}>{t('Note')}</span>
              &nbsp;
              {t('This is not a permanent error, you can ', true)}
              <span style={{ fontWeight: 'bold' }}>{t('retry')}</span>
            </div>
            <br />
          </>
        )}
      </>
    );
  }

  const testEmailModal = () => {
    const onFinish = async () => {
      try {
        await testReceiverForm.validateFields();
      } catch (error) {
        return;
      }

      setTestEmailSuccessMsg(undefined);
      setTestEmailFailureMsg(undefined);
      setTestEmailRetryMsg(undefined);
      setTestEmailModalvisible(false);
      try {
        const formSmtp = formRef.current!.getFieldFormatValue!().smtp!;
        const smtp = {
          ...formSmtp,
          base_url: get_base_url(),
          test_receiver: testReceiver,
        };
        setWaitingTestEmail(true);
        const resp = await updateTeamInfo({
          data: {
            smtp: smtp,
          }
        });
        setWaitingTestEmail(false);

        if (resp.code === 0) {
          message.success('Update SMTP Info successfully.');
          // If auth is not required (and not oauth2), do not show the detailed test result.
          if (smtp.requires_auth || smtp.oauth2_provider) {
            setTestEmailSuccessMsg(resp.msg);
          }
        } else {
          // If the code is not 0, the backend will not update the settings.
          message.error('Failed to update SMTP');
          if (resp.can_retry) {
            setTestEmailRetryMsg(resp.msg);
          } else {
            setTestEmailFailureMsg(resp.msg);
          }
        }
      } catch (error) {
        setWaitingTestEmail(false);
        message.error('Failed to update SMTP');
        setTestEmailFailureMsg('' + error);
      }
    }
    return <>
      <Modal
        title={t('The Receiver Email', true)}
        open={testEmailModalvisible}
        onCancel={() => { setTestEmailModalvisible(false) }}
        onOk={onFinish}
      >
        <Form form={testReceiverForm}>
          <Form.Item
            name={'The Receiver Email'}
            rules={[
              {
                required: true,
                whitespace: true,
              },
              {
                min: 4,
                max: 300,
              },
              {
                type: 'email',
              },
            ]}
            validateTrigger={['onBlur']}
          >
            <Input
              placeholder={'The Receiver Email'}
              onChange={(e) => {
                setTestReceiver(e.target.value);
              }}
              onPressEnter={onFinish}
            />
          </Form.Item>
        </Form>
      </Modal>
    </>;
  }

  return (
    <PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.Settings', true) },
          { title: t('SMTP', true) },
        ]} />
      )}
    >
      {loading ? null : (
        <Card>
          <ProForm<API.TeamInfo>
            layout="vertical"
            onFinish={handleFinish}
            formRef={formRef}
            labelCol={{ span: 24, offset: 0 }} labelAlign={"left"}
            submitter={{
              render: () => {
                return (
                  <>
                    <Space>
                      {formSubmitButton()}
                      {formSubmitAndTestButton()}
                    </Space>
                  </>
                );
              },
            }}
            request={async () => {
              try {
                const info = await queryTeamInfo();
                const url = get_base_url();
                if (info?.smtp?.base_url && info?.smtp?.base_url != url) {
                  info.smtp!.base_url = get_base_url();
                  try {
                    updateTeamInfo({ data: info }); // no wait
                  } catch (error) { }
                }
                if (info?.smtp?.requires_auth == undefined) {
                  if (info?.smtp) {
                    info.smtp.requires_auth = true;
                  } else if (info) {
                    info.smtp = { requires_auth: true };
                  }
                }
                setAccount(info?.smtp?.account || '');
                setPassword(info?.smtp?.password || '');
                setRequiresAuth(info?.smtp?.requires_auth == true);
                const provider = info?.smtp?.oauth2_provider || '';
                setOauth2Provider(provider);
                setOauth2Enabled(!!provider);
                if (info) {
                  return info;
                }
              } catch (error) {
                message.error(error as any);
              }
              return Promise.reject();
            }}
            onValuesChange={() => {
              setTestEmailSuccessMsg(undefined);
              setTestEmailFailureMsg(undefined);
            }}
          >
            {/* OAuth2 provider select: first thing to configure when OAuth2 is enabled */}
            {oauth2Enabled && (
              <ProFormSelect
                width="md"
                name={['smtp', 'oauth2_provider']}
                label={t('OAuth2 Provider', true)}
                options={[
                  { label: 'Microsoft 365', value: 'M365' },
                  { label: t('Custom', true), value: 'Custom' },
                ]}
                fieldProps={{
                  onChange: (value: string) => {
                    const nextProvider = value || '';
                    const providerChanged = nextProvider !== oauth2Provider;
                    setOauth2Provider(nextProvider);
                    const smtpPatch: any = {};
                    if (providerChanged) {
                      smtpPatch.oauth2_client_id = '';
                      smtpPatch.oauth2_client_secret = '';
                      smtpPatch.oauth2_tenant_id = '';
                      smtpPatch.oauth2_token_url = '';
                      smtpPatch.oauth2_scope = '';
                    }
                    smtpPatch.requires_auth = false;
                    smtpPatch.password = '';
                    setRequiresAuth(false);
                    if (Object.keys(smtpPatch).length > 0) {
                      formRef.current?.setFieldsValue({ smtp: smtpPatch });
                    }
                  }
                }}
              />
            )}
            {oauth2Enabled && formOauth2Fields()}
            {/* SMTP Host & Port: hidden when M365 is selected */}
            {!(oauth2Enabled && oauth2Provider === 'M365') && (
              <ProForm.Group>
                <ProFormText
                  fieldProps={{ autoComplete: 'off' }}
                  rules={[
                    {
                      required: true,
                      whitespace: true,
                    },
                    {
                      min: 4,
                      max: 100,
                    },
                  ]}
                  width="md"
                  placeholder={'email-smtp.eu-west-1.amazonaws.com'}
                  name={['smtp', 'host']}
                  label={t('SMTP Host', true)}
                />
                <ProFormDigit
                  label={t('SMTP Port', true)}
                  name={['smtp', 'port']}
                  width="md"
                  min={1}
                  max={65535}
                  placeholder={'465 / 587 (STARTTLS)'}
                />
              </ProForm.Group>
            )}
            <ProFormText
              fieldProps={{ autoComplete: 'off' }}
              rules={[
                {
                  required: true,
                  whitespace: true,
                },
                {
                  max: 300,
                },
                {
                  type: 'email',
                },
              ]}
              validateTrigger={['onBlur']}
              placeholder={'no-reply@example.com'}
              width="md"
              name={['smtp', 'from']}
              label={t('smtp.From', true, 'From')}
            />
            {!oauth2Enabled && (
              <ProFormCheckbox
                width="md"
                name={['smtp', 'requires_auth']}
                fieldProps={{
                  onChange: (e: CheckboxChangeEvent) => {
                    setRequiresAuth(e.target.checked);
                    if (e.target.checked) {
                      formRef.current?.setFieldsValue({ smtp: { account: account } });
                      formRef.current?.setFieldsValue({ smtp: { password: password } });
                    } else {
                      formRef.current?.setFieldsValue({ smtp: { account: '' } });
                      formRef.current?.setFieldsValue({ smtp: { password: '' } });
                    }
                  }
                }}
              >
                {t('My Server Requires Authentication', true)}
              </ProFormCheckbox>
            )}
            {(requiresAuth || oauth2Enabled) ? formAccountPassword() : null}
            {/* Custom Certificate PEM & Timeout */}
            <ProForm.Group>
              {!(oauth2Enabled && oauth2Provider === 'M365') && (
                <ProFormText
                  fieldProps={{ autoComplete: 'off' }}
                  rules={[
                    {
                      whitespace: true,
                    },
                  ]}
                  placeholder={''}
                  width="md"
                  name={['smtp', 'permfile']}
                  label={t('Custom Certificate PEM File Path (on the server)', true)}
                />
              )}
              <ProFormDigit
                label={t('Timeout (Seconds)', true)}
                name={['smtp', 'timeout_secs']}
                width="md"
                min={5}
                max={120}
                placeholder={'30'}
                fieldProps={{ precision: 0 }}
              />
            </ProForm.Group>
            {/* STARTTLS & OAuth2 checkboxes grouped together at the bottom */}
            <div style={{ display: 'flex', gap: 24 }}>
              {!(oauth2Enabled && oauth2Provider === 'M365') && (
                <ProFormCheckbox
                  name={['smtp', 'starttls']}
                >{t('STARTTLS', true)}</ProFormCheckbox>
              )}
              <ProFormCheckbox
                fieldProps={{
                  checked: oauth2Enabled,
                  onChange: (e: CheckboxChangeEvent) => {
                    const enabled = e.target.checked;
                    setOauth2Enabled(enabled);
                    if (!enabled) {
                      setOauth2Provider('');
                      formRef.current?.setFieldsValue({
                        smtp: {
                          oauth2_provider: '',
                          oauth2_client_id: '',
                          oauth2_client_secret: '',
                          oauth2_tenant_id: '',
                          oauth2_token_url: '',
                          oauth2_scope: '',
                        }
                      });
                    } else {
                      // Default to M365 when enabling
                      setOauth2Provider('M365');
                      setRequiresAuth(false);
                      formRef.current?.setFieldsValue({
                        smtp: {
                          oauth2_provider: 'M365',
                          requires_auth: false,
                          password: '',
                        }
                      });
                    }
                  }
                }}
              >
                {t('Use OAuth2 for authentication', true)}
              </ProFormCheckbox>
            </div>
            {testEmailResult()}
          </ProForm>
          {testEmailModal()}
        </Card>
      )
      }
    </PageContainer >
  );
};

export default SmtpView;
